  1→import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
  2→import { Badge } from '@/components/ui/badge';
  3→import { ProgressRing } from '@/components/shared/ProgressRing';
  4→import { Target, AlertTriangle, Lightbulb, TrendingDown, Compass } from 'lucide-react';
  5→import type { Insight } from '@/lib/types';
  6→import { parseJsonField } from '@/lib/types';
  7→
  8→interface PromptQualityCardProps {
  9→  insight: Insight;
 10→}
 11→
 12→interface AntiPattern {
 13→  name: string;
 14→  description?: string;
 15→  count: number;
 16→  examples: string[];
 17→  fix?: string;
 18→}
 19→
 20→interface WastedTurn {
 21→  messageIndex: number;
 22→  whatWentWrong?: string;
 23→  reason?: string;           // legacy v2 field
 24→  originalMessage?: string;
 25→  suggestedRewrite?: string;
 26→  turnsWasted?: number;
 27→}
 28→
 29→interface SessionTrait {
 30→  trait: string;
 31→  severity: 'high' | 'medium' | 'low';
 32→  description: string;
 33→  evidence?: string;
 34→  suggestion?: string;
 35→}
 36→
 37→const TRAIT_LABELS: Record<string, string> = {
 38→  context_drift: 'Context Drift',
 39→  objective_bloat: 'Objective Bloat',
 40→  late_context: 'Late Context',
 41→  no_planning: 'No Planning',
 42→  good_structure: 'Well Structured',
 43→};
 44→
 45→const SEVERITY_COLORS: Record<string, string> = {
 46→  high: 'text-red-500 bg-red-500/10 border-red-500/20',
 47→  medium: 'text-orange-500 bg-orange-500/10 border-orange-500/20',
 48→  low: 'text-yellow-500 bg-yellow-500/10 border-yellow-500/20',
 49→};
 50→
 51→import { getScoreTier, getScoreLabel } from '@/lib/score-utils';
 52→
 53→const SCORE_COLORS: Record<string, string> = {
 54→  excellent: 'text-green-500',
 55→  good: 'text-yellow-500',
 56→  fair: 'text-orange-500',
 57→  poor: 'text-red-500',
 58→};
 59→
 60→function getScoreColor(score: number): string {
 61→  return SCORE_COLORS[getScoreTier(score)];
 62→}
 63→
 64→export function PromptQualityCard({ insight }: PromptQualityCardProps) {
 65→  const metadata = parseJsonField<Record<string, unknown>>(insight.metadata, {});
 66→  const bullets = parseJsonField<string[]>(insight.bullets, []);
 67→
 68→  const score = typeof metadata.efficiencyScore === 'number' ? metadata.efficiencyScore : 0;
 69→  const wastedTurns = Array.isArray(metadata.wastedTurns) ? metadata.wastedTurns as WastedTurn[] : [];
 70→  const antiPatterns = Array.isArray(metadata.antiPatterns) ? metadata.antiPatterns as AntiPattern[] : [];
 71→  const sessionTraits = Array.isArray(metadata.sessionTraits) ? metadata.sessionTraits as SessionTrait[] : [];
 72→  const reduction = typeof metadata.potentialMessageReduction === 'number' ? metadata.potentialMessageReduction : 0;
 73→
 74→  return (
 75→    <Card className="border-rose-500/20">
 76→      <CardHeader className="pb-3">
 77→        <div className="flex items-start justify-between">
 78→          <div className="flex items-center gap-2">
 79→            <div className="rounded-md p-1.5 bg-rose-500/10 text-rose-500 border-rose-500/20">
 80→              <Target className="h-4 w-4" />
 81→            </div>
 82→            <CardTitle className="text-base">Prompt Quality Analysis</CardTitle>
 83→          </div>
 84→          <Badge variant="outline" className="bg-rose-500/10 text-rose-500 border-rose-500/20">
 85→            Prompt Quality
 86→          </Badge>
 87→        </div>
 88→      </CardHeader>
 89→
 90→      <CardContent className="space-y-4">
 91→        <div className="flex items-center gap-4">
 92→          <div className="text-center">
 93→            <ProgressRing value={score} />
 94→            <p className="text-xs text-muted-foreground mt-1">/100</p>
 95→          </div>
 96→          <div>
 97→            <p className={`text-sm font-medium ${getScoreColor(score)}`}>
 98→              {getScoreLabel(score)}
 99→            </p>
100→            <p className="text-sm text-muted-foreground">
101→              {insight.content}
102→            </p>
103→          </div>
104→        </div>
105→
106→        {reduction > 0 && (
107→          <div className="flex items-center gap-2 text-sm rounded-md bg-muted/50 p-2">
108→            <TrendingDown className="h-4 w-4 text-muted-foreground shrink-0" />
109→            <span>
110→              Could have been done in <strong>{reduction} fewer</strong> messages
111→            </span>
112→          </div>
113→        )}
114→
115→        {antiPatterns.length > 0 && (
116→          <div className="space-y-2">
117→            <div className="flex items-center gap-1.5 text-sm font-medium">
118→              <AlertTriangle className="h-3.5 w-3.5 text-orange-500" />
119→              Anti-Patterns Detected
120→            </div>
121→            <div className="space-y-1.5">
122→              {antiPatterns.map((pattern, i) => (
123→                <div key={i} className="text-sm rounded-md border p-2 space-y-1">
124→                  <div className="flex items-center justify-between">
125→                    <span className="font-medium">{pattern.name}</span>
126→                    <Badge variant="secondary" className="text-xs">
127→                      {pattern.count}x
128→                    </Badge>
129→                  </div>
130→                  {pattern.description && (
131→                    <p className="text-xs text-muted-foreground">{pattern.description}</p>
132→                  )}
133→                  {pattern.examples.length > 0 && (
134→                    <p className="text-xs text-muted-foreground mt-1 line-clamp-2">
135→                      e.g. &ldquo;{pattern.examples[0]}&rdquo;
136→                    </p>
137→                  )}
138→                  {pattern.fix && (
139→                    <p className="text-xs text-green-600 mt-1">Fix: {pattern.fix}</p>
140→                  )}
141→                </div>
142→              ))}
143→            </div>
144→          </div>
145→        )}
146→
147→        {sessionTraits.length > 0 && (
148→          <div className="space-y-2">
149→            <div className="flex items-center gap-1.5 text-sm font-medium">
150→              <Compass className="h-3.5 w-3.5 text-blue-500" />
151→              Session Traits
152→            </div>
153→            <div className="space-y-1.5">
154→              {sessionTraits.map((t, i) => (
155→                <div key={i} className="text-sm rounded-md border p-2 space-y-1">
156→                  <div className="flex items-center justify-between">
157→                    <span className="font-medium">{TRAIT_LABELS[t.trait] || t.trait}</span>
158→                    <Badge variant="outline" className={`text-xs ${
159→                      t.trait === 'good_structure'
160→                        ? 'text-green-500 bg-green-500/10 border-green-500/20'
161→                        : SEVERITY_COLORS[t.severity] || ''
162→                    }`}>
163→                      {t.trait === 'good_structure' ? 'positive' : t.severity}
164→                    </Badge>
165→                  </div>
166→                  <p className="text-xs text-muted-foreground">{t.description}</p>
167→                  {t.evidence && (
168→                    <p className="text-xs text-muted-foreground italic">{t.evidence}</p>
169→                  )}
170→                  {t.suggestion && (
171→                    <p className="text-xs text-green-600">Suggestion: {t.suggestion}</p>
172→                  )}
173→                </div>
174→              ))}
175→            </div>
176→          </div>
177→        )}
178→
179→        {wastedTurns.length > 0 && (
180→          <div className="space-y-2">
181→            <p className="text-sm font-medium">
182→              Wasted Turns ({wastedTurns.length})
183→            </p>
184→            <div className="space-y-2 max-h-48 overflow-y-auto">
185→              {wastedTurns.slice(0, 5).map((turn, i) => (
186→                <div key={i} className="text-sm rounded-md border p-2 space-y-1">
187→                  <div className="flex items-center gap-2">
188→                    <Badge variant="outline" className="text-xs shrink-0">
189→                      Msg #{turn.messageIndex + 1}
190→                      {turn.turnsWasted && turn.turnsWasted > 1 ? ` (${turn.turnsWasted} turns)` : ''}
191→                    </Badge>
192→                    <span className="text-muted-foreground">{turn.whatWentWrong || turn.reason}</span>
193→                  </div>
194→                  {turn.originalMessage && (
195→                    <p className="text-xs text-muted-foreground italic line-clamp-2">
196→                      &ldquo;{turn.originalMessage}&rdquo;
197→                    </p>
198→                  )}
199→                  {turn.suggestedRewrite && (
200→                    <details className="text-xs">
201→                      <summary className="cursor-pointer text-muted-foreground hover:text-foreground">
202→                        Better prompt
203→                      </summary>
204→                      <p className="mt-1 bg-muted/50 rounded p-1.5">
205→                        {turn.suggestedRewrite}
206→                      </p>
207→                    </details>
208→                  )}
209→                </div>
210→              ))}
211→              {wastedTurns.length > 5 && (
212→                <p className="text-xs text-muted-foreground">
213→                  +{wastedTurns.length - 5} more wasted turns...
214→                </p>
215→              )}
216→            </div>
217→          </div>
218→        )}
219→
220→        {bullets.length > 0 && (
221→          <div className="space-y-2">
222→            <div className="flex items-center gap-1.5 text-sm font-medium">
223→              <Lightbulb className="h-3.5 w-3.5 text-yellow-500" />
224→              Tips
225→            </div>
226→            <ul className="list-disc list-inside space-y-1 text-sm text-muted-foreground">
227→              {bullets.map((tip, i) => (
228→                <li key={i}>{tip}</li>
229→              ))}
230→            </ul>
231→          </div>
232→        )}
233→      </CardContent>
234→    </Card>
235→  );
236→}
