      const arr = groups.get(key) || [];
      arr.push(insight);
      groups.set(key, arr);
    }

    const entries = [...groups.entries()];

    if (view === 'timeline') {
      const sorted = sortDateGroups(entries);
      return sorted.map(([key, items]) => ({
        key,
        label: key,
        count: items.length,
        insights: items,
